1	package graph
2	
3	import (
4		"fmt"
5		"slices"
6		"strings"
7	
8		"github.com/go-logr/logr"
9		"k8s.io/apimachinery/pkg/types"
10		"k8s.io/apimachinery/pkg/util/validation/field"
11		v1 "sigs.k8s.io/gateway-api/apis/v1"
12	
13		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
14		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/resolver"
15		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
16	)
17	
18	type BackendTLSPolicy struct {
19		// Source is the source resource.
20		Source *v1.BackendTLSPolicy
21		// CaCertRef is the name of the ConfigMap that contains the CA certificate.
22		CaCertRef types.NamespacedName
23		// Gateways are the names of the Gateways for which this BackendTLSPolicy is effectively applied.
24		// Only contains gateways where the policy can be applied (not limited by ancestor status).
25		Gateways []types.NamespacedName
26		// Conditions include Conditions for the BackendTLSPolicy.
27		Conditions []conditions.Condition
28		// Valid shows whether the BackendTLSPolicy is valid.
29		Valid bool
30		// IsReferenced shows whether the BackendTLSPolicy is referenced by a BackendRef.
31		IsReferenced bool
32		// Ignored shows whether the BackendTLSPolicy is ignored.
33		Ignored bool
34	}
35	
36	func processBackendTLSPolicies(
37		backendTLSPolicies map[types.NamespacedName]*v1.BackendTLSPolicy,
38		resourceResolver resolver.Resolver,
39		gateways map[types.NamespacedName]*Gateway,
40	) map[types.NamespacedName]*BackendTLSPolicy {
41		if len(backendTLSPolicies) == 0 || len(gateways) == 0 {
42			return nil
43		}
44	
45		processedBackendTLSPolicies := make(map[types.NamespacedName]*BackendTLSPolicy, len(backendTLSPolicies))
46		for nsname, backendTLSPolicy := range backendTLSPolicies {
47			var caCertRef types.NamespacedName
48	
49			valid, ignored, conds := validateBackendTLSPolicy(backendTLSPolicy, resourceResolver)
50	
51			if valid && !ignored && backendTLSPolicy.Spec.Validation.CACertificateRefs != nil {
52				caCertRef = types.NamespacedName{
53					Namespace: backendTLSPolicy.Namespace, Name: string(backendTLSPolicy.Spec.Validation.CACertificateRefs[0].Name),
54				}
55			}
56	
57			processedBackendTLSPolicies[nsname] = &BackendTLSPolicy{
58				Source:     backendTLSPolicy,
59				Valid:      valid,
60				Conditions: conds,
61				CaCertRef:  caCertRef,
62				Ignored:    ignored,
63			}
64		}
65		return processedBackendTLSPolicies
66	}
67	
68	func validateBackendTLSPolicy(
69		backendTLSPolicy *v1.BackendTLSPolicy,
70		resourceResolver resolver.Resolver,
71	) (valid, ignored bool, conds []conditions.Condition) {
72		valid = true
73		ignored = false
74	
75		if err := validateBackendTLSHostname(backendTLSPolicy); err != nil {
76			valid = false
77			conds = append(conds, conditions.NewPolicyInvalid(fmt.Sprintf("Invalid hostname: %s", err.Error())))
78		}
79	
80		caCertRefs := backendTLSPolicy.Spec.Validation.CACertificateRefs
81		wellKnownCerts := backendTLSPolicy.Spec.Validation.WellKnownCACertificates
82	
83		// Check mutual exclusivity
84		switch {
85		case len(caCertRefs) > 0 && wellKnownCerts != nil:
86			valid = false
87			msg := "CACertificateRefs and WellKnownCACertificates are mutually exclusive"
88			conds = append(conds, conditions.NewPolicyInvalid(msg))
89	
90		case len(caCertRefs) > 0:
91			certConds := validateBackendTLSCACertRef(backendTLSPolicy, resourceResolver)
92			if len(certConds) > 0 {
93				valid = false
94				conds = append(conds, certConds...)
95			} else if valid {
96				// Only set ResolvedRefs to true if CACertificateRefs are valid AND overall policy is valid
97				conds = append(conds, conditions.NewBackendTLSPolicyResolvedRefs())
98			}
99	
100		case wellKnownCerts != nil:
101			if err := validateBackendTLSWellKnownCACerts(backendTLSPolicy); err != nil {
102				valid = false
103				conds = append(conds, conditions.NewPolicyInvalid(
104					fmt.Sprintf("invalid WellKnownCACertificates: %s", err.Error())))
105			}
106	
107		default:
108			valid = false
109			conds = append(
110				conds,
111				conditions.NewPolicyInvalid("Either CACertificateRefs or WellKnownCACertificates must be specified"),
112			)
113		}
114	
115		return valid, ignored, conds
116	}
117	
118	func validateBackendTLSHostname(btp *v1.BackendTLSPolicy) error {
119		h := string(btp.Spec.Validation.Hostname)
120	
121		if err := validateHostname(h); err != nil {
122			path := field.NewPath("tls.hostname")
123			valErr := field.Invalid(path, btp.Spec.Validation.Hostname, err.Error())
124			return valErr
125		}
126		return nil
127	}
128	
129	func validateBackendTLSCACertRef(
130		btp *v1.BackendTLSPolicy,
131		resourceResolver resolver.Resolver,
132	) []conditions.Condition {
133		if len(btp.Spec.Validation.CACertificateRefs) != 1 {
134			path := field.NewPath("validation.caCertificateRefs")
135			valErr := field.TooMany(path, len(btp.Spec.Validation.CACertificateRefs), 1)
136			return []conditions.Condition{conditions.NewPolicyInvalid(valErr.Error())}
137		}
138	
139		selectedCertRef := btp.Spec.Validation.CACertificateRefs[0]
140		allowedCaCertKinds := []v1.Kind{"ConfigMap", "Secret"}
141	
142		if !slices.Contains(allowedCaCertKinds, selectedCertRef.Kind) {
143			path := field.NewPath("validation.caCertificateRefs[0].kind")
144			valErr := field.NotSupported(path, btp.Spec.Validation.CACertificateRefs[0].Kind, allowedCaCertKinds)
145			return []conditions.Condition{
146				conditions.NewBackendTLSPolicyInvalidKind(valErr.Error()),
147				conditions.NewBackendTLSPolicyNoValidCACertificate("No valid CACertificateRef found"),
148			}
149		}
150		if selectedCertRef.Group != "" &&
151			selectedCertRef.Group != "core" {
152			path := field.NewPath("validation.caCertificateRefs[0].group")
153			valErr := field.NotSupported(path, selectedCertRef.Group, []string{"", "core"})
154			return []conditions.Condition{
155				conditions.NewBackendTLSPolicyInvalidKind(valErr.Error()),
156				conditions.NewBackendTLSPolicyNoValidCACertificate("No valid CACertificateRef found"),
157			}
158		}
159		nsName := types.NamespacedName{
160			Namespace: btp.Namespace,
161			Name:      string(selectedCertRef.Name),
162		}
163	
164		if err := resourceResolver.Resolve(resolver.ResourceType(selectedCertRef.Kind), nsName); err != nil {
165			path := field.NewPath("validation.caCertificateRefs[0]")
166			valErr := field.Invalid(path, selectedCertRef, err.Error())
167			return []conditions.Condition{
168				conditions.NewBackendTLSPolicyInvalidCACertificateRef(valErr.Error()),
169				conditions.NewBackendTLSPolicyNoValidCACertificate("No valid CACertificateRef found"),
170			}
171		}
172	
173		return nil
174	}
175	
176	func validateBackendTLSWellKnownCACerts(btp *v1.BackendTLSPolicy) error {
177		if *btp.Spec.Validation.WellKnownCACertificates != v1.WellKnownCACertificatesSystem {
178			path := field.NewPath("tls.wellknowncacertificates")
179			return field.NotSupported(
180				path,
181				btp.Spec.Validation.WellKnownCACertificates,
182				[]string{string(v1.WellKnownCACertificatesSystem)},
183			)
184		}
185		return nil
186	}
187	
188	// countNonNGFAncestors counts the number of non-NGF ancestors in policy status.
189	func countNonNGFAncestors(policy *v1.BackendTLSPolicy, ctlrName string) int {
190		nonNGFCount := 0
191		for _, ancestor := range policy.Status.Ancestors {
192			if string(ancestor.ControllerName) != ctlrName {
193				nonNGFCount++
194			}
195		}
196		return nonNGFCount
197	}
198	
199	// addPolicyAncestorLimitCondition adds or updates a PolicyAncestorLimitReached condition.
200	func addPolicyAncestorLimitCondition(
201		conds []conditions.Condition,
202		policyName string,
203		policyType string,
204	) []conditions.Condition {
205		for i, condition := range conds {
206			if condition.Reason == string(conditions.PolicyReasonAncestorLimitReached) {
207				if !strings.Contains(condition.Message, policyName) {
208					conds[i].Message = fmt.Sprintf("%s, %s %s", condition.Message, policyType, policyName)
209				}
210				return conds
211			}
212		}
213	
214		newCondition := conditions.NewPolicyAncestorLimitReached(policyType, policyName)
215		return append(conds, newCondition)
216	}
217	
218	// collectOrderedGateways collects gateways in spec order (services) then creation time order (gateways within service).
219	func collectOrderedGateways(
220		policy *v1.BackendTLSPolicy,
221		services map[types.NamespacedName]*ReferencedService,
222		gateways map[types.NamespacedName]*Gateway,
223		existingNGFGatewayAncestors map[types.NamespacedName]struct{},
224	) []types.NamespacedName {
225		seenGateways := make(map[types.NamespacedName]struct{})
226		existingGateways := make([]types.NamespacedName, 0)
227		newGateways := make([]types.NamespacedName, 0)
228	
229		// Process services in spec order to maintain deterministic gateway ordering
230		for _, refs := range policy.Spec.TargetRefs {
231			if refs.Kind != kinds.Service {
232				continue
233			}
234	
235			svcNsName := types.NamespacedName{
236				Namespace: policy.Namespace,
237				Name:      string(refs.Name),
238			}
239	
240			referencedService, exists := services[svcNsName]
241			if !exists {
242				continue
243			}
244	
245			// Add to ordered lists, categorizing existing vs new, skipping duplicates
246			for gateway := range referencedService.GatewayNsNames {
247				if _, seen := seenGateways[gateway]; seen {
248					continue
249				}
250				seenGateways[gateway] = struct{}{}
251				if _, exists := existingNGFGatewayAncestors[gateway]; exists {
252					existingGateways = append(existingGateways, gateway)
253				} else {
254					newGateways = append(newGateways, gateway)
255				}
256			}
257		}
258	
259		sortGatewaysByCreationTime(existingGateways, gateways)
260		sortGatewaysByCreationTime(newGateways, gateways)
261	
262		return append(existingGateways, newGateways...)
263	}
264	
265	func extractExistingNGFGatewayAncestors(
266		backendTLSPolicy *v1.BackendTLSPolicy,
267		ctlrName string,
268	) map[types.NamespacedName]struct{} {
269		existingNGFGatewayAncestors := make(map[types.NamespacedName]struct{})
270	
271		for _, ancestor := range backendTLSPolicy.Status.Ancestors {
272			if string(ancestor.ControllerName) != ctlrName {
273				continue
274			}
275	
276			if ancestor.AncestorRef.Kind != nil && *ancestor.AncestorRef.Kind == v1.Kind(kinds.Gateway) &&
277				ancestor.AncestorRef.Namespace != nil {
278				gatewayNsName := types.NamespacedName{
279					Namespace: string(*ancestor.AncestorRef.Namespace),
280					Name:      string(ancestor.AncestorRef.Name),
281				}
282				existingNGFGatewayAncestors[gatewayNsName] = struct{}{}
283			}
284		}
285	
286		return existingNGFGatewayAncestors
287	}
288	
289	func addGatewaysForBackendTLSPolicies(
290		backendTLSPolicies map[types.NamespacedName]*BackendTLSPolicy,
291		services map[types.NamespacedName]*ReferencedService,
292		ctlrName string,
293		gateways map[types.NamespacedName]*Gateway,
294		logger logr.Logger,
295	) {
296		for _, backendTLSPolicy := range backendTLSPolicies {
297			existingNGFGatewayAncestors := extractExistingNGFGatewayAncestors(backendTLSPolicy.Source, ctlrName)
298			orderedGateways := collectOrderedGateways(
299				backendTLSPolicy.Source,
300				services,
301				gateways,
302				existingNGFGatewayAncestors,
303			)
304	
305			ancestorCount := countNonNGFAncestors(backendTLSPolicy.Source, ctlrName)
306	
307			// Process each gateway, respecting ancestor limits
308			for _, gatewayNsName := range orderedGateways {
309				// Check if adding this gateway would exceed the ancestor limit
310				if ancestorCount >= maxAncestors {
311					policyName := backendTLSPolicy.Source.Namespace + "/" + backendTLSPolicy.Source.Name
312					proposedAncestor := createParentReference(v1.GroupName, kinds.Gateway, gatewayNsName)
313					gatewayName := getAncestorName(proposedAncestor)
314	
315					if gateway, ok := gateways[gatewayNsName]; ok {
316						gateway.Conditions = addPolicyAncestorLimitCondition(gateway.Conditions, policyName, kinds.BackendTLSPolicy)
317					} else {
318						// This should never happen, but we'll log it if it does
319						logger.Error(fmt.Errorf("gateway not found in the graph"),
320							"Gateway not found in the graph", "policy", policyName, "ancestor", gatewayName)
321					}
322	
323					logAncestorLimitReached(logger, policyName, "BackendTLSPolicy", gatewayName)
324					continue
